import { describe, expect, it, vi } from "vitest";
import { renderToStaticMarkup } from "react-dom/server";

vi.mock("next/navigation", () => ({ useRouter: () => ({ push: vi.fn(), refresh: vi.fn() }) }));

import { CartView } from "./CartView";

describe("<CartView />", () => {
  it("renders the empty-state with the Browse medicines CTA when the cart is empty", () => {
    const html = renderToStaticMarkup(
      <CartView initialCart={{ groups: [], grandTotalPaise: 0, itemCount: 0 }} />,
    );
    expect(html).toContain("Your cart is empty");
    expect(html).toContain("Browse medicines");
    expect(html).toContain('href="/dashboard/home"');
  });
});

import { describe, expect, it, vi } from "vitest";
import { renderToStaticMarkup } from "react-dom/server";

vi.mock("next/navigation", () => ({ useRouter: () => ({ push: vi.fn(), refresh: vi.fn() }) }));

import { CartView } from "./CartView";

describe("<CartView /> grouped state", () => {
  it("renders distributor heading, per-line totals, and the Place order pill", () => {
    const html = renderToStaticMarkup(
      <CartView
        initialCart={{
          groups: [
            {
              distributor: { id: "d-mediplus", name: "MediPlus Distributors" },
              items: [
                { medicineId: "m-paracetamol-500", name: "Paracetamol 500mg", brand: "Crocin", qty: 2, unitPricePaise: 2200, lineTotalPaise: 4400 },
              ],
              subtotalPaise: 4400,
            },
          ],
          grandTotalPaise: 4400,
          itemCount: 2,
        }}
      />,
    );
    expect(html).toContain("MediPlus Distributors");
    expect(html).toContain("Paracetamol 500mg");
    expect(html).toContain("Remove");
    expect(html).toContain("Place order (2)");
    expect(html).toContain("\u20B944.00");
  });
});
